const express = require("express");
const morgan = require("morgan");
const APIKEY = "e16906387a0cc1bcd5c55b39ba76cbe07d4f2f0c";


  const getMeals = () => {
    return fetch(`https://api.spoonacular.com/recipes/random?apiKey=${APIKEY}&number=5`).then((res) => res.json());
  }



express()
    .use(morgan("tiny"))
    .use(require("body-parser").json())
    .use(express.static("public"))

    .get(`/`, (req, res) => {
        res.send("Let's see what this leads me to!")
    })


    .get(`*`, (req, res) => {
        res.status(404).json({
            status: 404,
            message: "This is quite obviously the wrong page! It does not exist!",
        });
    })

    .listen(8000, () => {console.log(`Listening on port 8000`)});

    export default getMeals;
